10	const payloadMethods = new Set(
11	  Object.freeze(["PATCH", "POST", "PUT", "DELETE"])
12	);
13	export function isPayloadMethod(method = "GET"): boolean {
14	  return payloadMethods.has(method.toUpperCase());
15	}
