  CircuitBreakerOptions,
  CircuitBreakerRecord,
  CircuitBreakerStore,
  CircuitBreakerTicket,
  FetchRequest,
} from "./types.ts";

export const DEFAULT_CIRCUIT_BREAKER_FAILURE_STATUS_CODES = [
  408, 409, 425, 429, 500, 502, 503, 504,
];

interface ResolvedCircuitBreakerConfig {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export function resolveCircuitBreakerConfig(
  option: true | CircuitBreakerOptions
): ResolvedCircuitBreakerConfig {
  if (option === true) {
    return {
      threshold: 5,
      cooldown: 30_000,
      halfOpenMaxRequests: 1,
      failureStatusCodes: DEFAULT_CIRCUIT_BREAKER_FAILURE_STATUS_CODES,
    };
  }
  return {
    threshold: option.threshold ?? 5,
    cooldown: option.cooldown ?? 30_000,
    halfOpenMaxRequests: option.halfOpenMaxRequests ?? 1,
    failureStatusCodes:
      option.failureStatusCodes ?? DEFAULT_CIRCUIT_BREAKER_FAILURE_STATUS_CODES,
  };
}

export function resolveRequestOrigin(request: FetchRequest): string {
  const url =
    typeof request === "string"
      ? request
      : request instanceof URL
        ? request.href
        : (request as Request).url;
  try {
    return new URL(url).origin;
  } catch {
    return url;
  }
}

function getOrCreateRecord(
  store: CircuitBreakerStore,
  origin: string
): CircuitBreakerRecord {
  let record = store.get(origin);
  if (!record) {
    record = {
      status: "closed",
      failures: 0,
      nextAttempt: 0,
      halfOpenInFlight: 0,
    };
    store.set(origin, record);
  }
  return record;
}

export type CircuitBreakerAcquireResult =
  | { blocked: true; origin: string }
  | { blocked: false; ticket: CircuitBreakerTicket };

export function acquireCircuitBreakerTicket(
  store: CircuitBreakerStore,
  request: FetchRequest,
  option: true | CircuitBreakerOptions
): CircuitBreakerAcquireResult {
  const config = resolveCircuitBreakerConfig(option);
  const origin = resolveRequestOrigin(request);
  const record = getOrCreateRecord(store, origin);

  if (record.status === "open" && Date.now() >= record.nextAttempt) {
    record.status = "half-open";
    record.halfOpenInFlight = 0;
  }

  if (record.status === "open") {
    return { blocked: true, origin };
  }

  if (record.status === "half-open") {
    if (record.halfOpenInFlight >= config.halfOpenMaxRequests) {
      return { blocked: true, origin };
    }
    record.halfOpenInFlight++;
    return {
      blocked: false,
      ticket: { origin, store, config, isHalfOpenProbe: true, released: false },
    };
  }

  return {
    blocked: false,
    ticket: { origin, store, config, isHalfOpenProbe: false, released: false },
  };
}

export type CircuitBreakerOutcome = "success" | "failure" | "neutral";

export function releaseCircuitBreakerTicket(
  ticket: CircuitBreakerTicket,
  outcome: CircuitBreakerOutcome
): void {
  if (ticket.released) {
    return;
  }
  ticket.released = true;

  const record = ticket.store.get(ticket.origin);
  if (!record) {
    return;
  }

  if (ticket.isHalfOpenProbe) {
    record.halfOpenInFlight = Math.max(0, record.halfOpenInFlight - 1);
  }

  if (outcome === "success") {
    record.failures = 0;
    record.status = "closed";
    return;
  }

  if (outcome === "failure") {
    if (ticket.isHalfOpenProbe) {
      record.status = "open";
      record.nextAttempt = Date.now() + ticket.config.cooldown;
      return;
    }
    record.failures++;
    if (record.failures >= ticket.config.threshold) {
      record.status = "open";
      record.nextAttempt = Date.now() + ticket.config.cooldown;
    }
  }

  // outcome === "neutral": slot released above, no failure/state change.
}

export function isCircuitBreakerFailureStatus(
  ticket: CircuitBreakerTicket,
  status: number | undefined
): boolean {
  return status !== undefined && ticket.config.failureStatusCodes.includes(status);
}

export function createCircuitBreakerStore(): CircuitBreakerStore {
  return new Map<string, CircuitBreakerRecord>();
}

export type { CircuitBreakerRecord, CircuitBreakerTicket };
